(function(){
  'use strict';
  var VERSION='KG-2026-07-06-0006-debug';
  var TARGET='#keygen-app';
  var DEFAULTS={primary:'A',secondary:'Ф',keyboard:'Redragon K580RGB',keySize:'1u',nozzle:'0.2 mm FDM'};
  var CSS='.kwkg-root{box-sizing:border-box;width:100%;min-height:460px;padding:24px;border:1px solid rgba(255,255,255,.14);border-radius:18px;background:radial-gradient(circle at top left,rgba(128,22,255,.18),transparent 34%),#101014;color:#f4f0ff;font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}.kwkg-root *{box-sizing:border-box}.kwkg-header{display:flex;justify-content:space-between;gap:16px;margin-bottom:22px}.kwkg-kicker{margin:0 0 6px;color:#bfa7ff;font-size:12px;letter-spacing:.16em;text-transform:uppercase}.kwkg-title{margin:0;font-size:clamp(28px,4vw,44px);line-height:1}.kwkg-subtitle{margin:10px 0 0;max-width:680px;color:#c8c2d8}.kwkg-grid{display:grid;grid-template-columns:minmax(0,1fr) minmax(280px,360px);gap:20px}.kwkg-panel{border:1px solid rgba(255,255,255,.12);border-radius:14px;background:rgba(255,255,255,.045);padding:18px}.kwkg-preview{display:grid;min-height:320px;place-items:center}.kwkg-keycap{position:relative;width:min(72vw,360px);aspect-ratio:1/.86;border-radius:18% 18% 24% 24%;background:linear-gradient(145deg,#17171b,#08080a);box-shadow:inset 0 0 0 2px #2b2b34,inset 0 -28px 44px rgba(255,255,255,.05),0 26px 70px rgba(0,0,0,.42)}.kwkg-primary,.kwkg-secondary{position:absolute;transform:translate(-50%,-50%);line-height:1;text-shadow:0 0 18px rgba(255,255,255,.9),0 0 42px rgba(167,121,255,.5)}.kwkg-primary{left:50%;top:48%;font-size:104px;color:#fff;font-weight:700}.kwkg-secondary{left:76%;top:24%;font-size:38px;color:rgba(220,206,255,.7);font-weight:600}.kwkg-control{display:grid;gap:7px;margin-bottom:14px}.kwkg-control label{color:#d7d0e7;font-size:13px}.kwkg-input{width:100%;border:1px solid rgba(255,255,255,.16);border-radius:10px;background:rgba(0,0,0,.32);color:#fff;padding:10px 12px;font:inherit}.kwkg-buttons{display:grid;gap:10px;margin-top:16px}.kwkg-button{border:1px solid rgba(255,255,255,.18);border-radius:999px;background:#f0e7ff;color:#111014;cursor:pointer;font:inherit;font-weight:700;padding:10px 14px}.kwkg-button[disabled]{cursor:not-allowed;opacity:.45}.kwkg-meta,.kwkg-issues{margin:12px 0 0;color:#bcb5ca;font-size:13px}.kwkg-debug{margin:14px 0 0;padding:10px 12px;border-radius:10px;background:rgba(255,255,255,.08);color:#d9d1ee;font-size:12px;word-break:break-word}@media(max-width:760px){.kwkg-grid{grid-template-columns:1fr}.kwkg-header{display:block}}';
  function addStyles(){if(document.getElementById('kwkg-styles'))return;var s=document.createElement('style');s.id='kwkg-styles';s.textContent=CSS;document.head.appendChild(s)}
  function spec(root){var p=root.querySelector('[data-kwkg-input="primary"]');var s=root.querySelector('[data-kwkg-input="secondary"]');return{version:VERSION,target:DEFAULTS.keyboard,keySize:DEFAULTS.keySize,nozzle:DEFAULTS.nozzle,primary:p&&p.value?p.value:DEFAULTS.primary,secondary:s&&s.value?s.value:DEFAULTS.secondary}}
  function update(root){var data=spec(root);var p=root.querySelector('[data-kwkg-preview="primary"]');var s=root.querySelector('[data-kwkg-preview="secondary"]');var issues=root.querySelector('[data-kwkg-issues]');if(p)p.textContent=data.primary;if(s)s.textContent=data.secondary;if(issues)issues.textContent=data.primary.trim()?'Prototype check: script loaded, mount succeeded, no blocking validation issues.':'Primary legend text is required.'}
  function download(root){var blob=new Blob([JSON.stringify(spec(root),null,2)],{type:'application/json'});var url=URL.createObjectURL(blob);var a=document.createElement('a');a.href=url;a.download='keygen-dev-spec.json';a.click();URL.revokeObjectURL(url)}
  function showFatal(message){var box=document.createElement('div');box.style.cssText='box-sizing:border-box;margin:16px 0;padding:16px;border:1px solid #ff8a8a;border-radius:12px;background:#240b0b;color:#ffdede;font-family:ui-sans-serif,system-ui,sans-serif';box.textContent='KeyGen failed to mount: '+message;document.body.appendChild(box)}
  function mount(target){try{var root=target instanceof HTMLElement?target:document.querySelector(target||TARGET);if(!root){showFatal('missing #keygen-app container');return}addStyles();root.classList.add('kwkg-root');root.setAttribute('data-keygen-mounted',VERSION);root.innerHTML='<header class="kwkg-header"><div><p class="kwkg-kicker">Knight Witch / KeyGen Prototype</p><h1 class="kwkg-title">Dual-Legend Keycap Generator</h1><p class="kwkg-subtitle">Direct embed test shell for a Redragon K580RGB 1u FDM keycap. Geometry export is disabled until the generator core is added.</p></div><p class="kwkg-meta">'+VERSION+'</p></header><div class="kwkg-grid"><section class="kwkg-panel kwkg-preview"><div class="kwkg-keycap"><span class="kwkg-primary" data-kwkg-preview="primary"></span><span class="kwkg-secondary" data-kwkg-preview="secondary"></span></div></section><aside class="kwkg-panel"><div class="kwkg-control"><label for="kwkg-primary">Primary legend</label><input id="kwkg-primary" class="kwkg-input" data-kwkg-input="primary" maxlength="4" value="A"></div><div class="kwkg-control"><label for="kwkg-secondary">Secondary legend</label><input id="kwkg-secondary" class="kwkg-input" data-kwkg-input="secondary" maxlength="4" value="Ф"></div><p class="kwkg-meta">Target: Redragon K580RGB / 1u / 0.2 mm FDM</p><p class="kwkg-issues" data-kwkg-issues></p><div class="kwkg-buttons"><button class="kwkg-button" type="button" data-kwkg-download>Download dev spec JSON</button><button class="kwkg-button" type="button" disabled>STL export pending geometry core</button><button class="kwkg-button" type="button" disabled>3MF export pending geometry core</button></div><p class="kwkg-debug">Debug: '+VERSION+' mounted from '+(document.currentScript&&document.currentScript.src?document.currentScript.src:'inline or cached script')+'</p></aside></div>';root.querySelectorAll('[data-kwkg-input]').forEach(function(i){i.addEventListener('input',function(){update(root)})});var button=root.querySelector('[data-kwkg-download]');if(button)button.addEventListener('click',function(){download(root)});update(root)}catch(error){showFatal(error&&error.message?error.message:String(error))}}
  window.__KEYGEN_EMBED_LOADED__=VERSION;
  window.KeyGen={version:VERSION,mount:mount,getSpec:function(){var root=document.querySelector(TARGET);return root?spec(root):null}};
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',function(){mount()});else mount();
})();
